  "guide.showEverything": "Mostrar todo",
  "guide.watchInActionTitle": "Véalo en acción",
  "guide.watchInActionDesc": "Grabaciones reales de la plataforma en vivo con recorridos narrados. Vea exactamente cómo se ve cada portal.",
  "guide.videoNoSupport": "Su navegador no admite la reproducción de video.",
  "guide.videoPublicTitle": "Sitio web público",
